<div class="card-dark"><h5>Entrega de materiales</h5><form method="post" action="<?= url('entregas-materiales/guardar') ?>" class="row g-2"><?= csrf_field() ?><div class="col-md-4"><label>Usuario receptor</label><select name="usuario_receptor_id" class="form-select"><?php foreach($usuarios as $u): ?><option value="<?= $u['id'] ?>"><?= e($u['nombre'].' '.$u['apellido']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label>Fecha entrega</label><input type="date" name="fecha_entrega" class="form-control" value="<?= date('Y-m-d') ?>"></div><div class="col-md-5"><label>Observación</label><input name="observacion" class="form-control"></div><div class="col-12"><h6>Detalle</h6><div id="detailRows"><div class="row g-2 mb-1"><div class="col-md-8"><select name="material_id[]" class="form-select"><?php foreach($materiales as $m): ?><option value="<?= $m['id'] ?>"><?= e($m['nombre_material']) ?> (<?= e($m['stock_actual']) ?>)</option><?php endforeach; ?></select></div><div class="col-md-2"><input type="number" step="0.01" name="cantidad[]" class="form-control" placeholder="Cantidad"></div></div></div><button type="button" class="btn btn-sm btn-outline-light" onclick="addDetail()">Agregar material</button></div><div><button class="btn btn-seim">Guardar entrega</button></div></form></div>
